<?php

namespace Database\Seeders;

use Illuminate\Database\Seeder;
use Illuminate\Support\Facades\DB;

class GeospatialMarkerSeeder extends Seeder
{
    /**
     * Seed the geospatial markers using compressed data.
     */
                public function run(): void
    {
        ini_set('memory_limit', '-1');

        $this->command->info('Decompressing and seeding Geospatial Markers...');

        // Base64 encoded, Raw Deflate compressed CSV data.
        $encodedData = '

';

        $mappingPath = database_path('seeders/data/beat_to_office_mapping.json');
        if (!file_exists($mappingPath)) {
            $this->command->error('Mapping file not found!');
            return;
        }

        $mapping = json_decode(file_get_contents($mappingPath), true);
        
        // Build office lookup: zone > sector > beat -> id
        $offices = DB::table('offices')
            ->join('offices as sectors', 'offices.parent_id', '=', 'sectors.id')
            ->join('offices as zones', 'sectors.parent_id', '=', 'zones.id')
            ->where('offices.type', 'BEAT')
            ->select('offices.id', 'offices.name as beat', 'sectors.name as sector', 'zones.name as zone')
            ->get();

        $officeLookup = [];
        foreach ($offices as $office) {
            $key = "{$office->zone}|{$office->sector}|{$office->beat}";
            $officeLookup[$key] = $office->id;
        }

        $decoded = base64_decode(trim($encodedData));
        $decompressed = gzinflate($decoded);
        
        if ($decompressed === false) {
            $this->command->error('Decompression failed!');
            return;
        }

        $lines = explode("
", $decompressed);
        $batchSize = 1000;
        $batch = [];
        $total = 0;

        DB::table('geospatial_markers')->truncate();

        foreach ($lines as $line) {
            if (empty(trim($line))) continue;
            
            $data = str_getcsv($line);
            if (count($data) < 6) continue;

            // CSV format: id, km, lat, long, landmark_name, beat_id
            $legacyBeatId = $data[5];
            $mapEntry = $mapping[$legacyBeatId] ?? null;

            if ($mapEntry) {
                $lookupKey = "{$mapEntry['zone']}|{$mapEntry['sector']}|{$mapEntry['beat']}";
                $officeId = $officeLookup[$lookupKey] ?? null;

                if ($officeId) {
                    $landmarkName = $data[4];
                    $side = null;
                    if (str_contains($landmarkName, '-North')) $side = 'N';
                    elseif (str_contains($landmarkName, '-South')) $side = 'S';
                    elseif (str_contains($landmarkName, '-East')) $side = 'E';
                    elseif (str_contains($landmarkName, '-West')) $side = 'W';

                    $batch[] = [
                        'office_id'      => $officeId,
                        'km'             => (float) $data[1],
                        'lat'            => (float) $data[2],
                        'lng'            => (float) $data[3],
                        'side'           => $side,
                        'created_at'     => now(),
                        'updated_at'     => now(),
                    ];
                    $total++;
                }
            }

            if (count($batch) >= $batchSize) {
                DB::table('geospatial_markers')->insert($batch);
                $batch = [];
            }
        }

        if (count($batch) > 0) {
            DB::table('geospatial_markers')->insert($batch);
        }

        $this->command->info("Seeded {$total} geospatial markers successfully.");
    }
}
